import * as d3 from 'd3';

const data = [30, 80, 45, 60, 20, 90, 55];
const width = 400, height = 200, margin = { top: 10, right: 10, bottom: 20, left: 30 };

const svg = d3.select('#chart').append('svg')
  .attr('width', width).attr('height', height);

const x = d3.scaleBand().domain(d3.range(data.length)).range([margin.left, width - margin.right]).padding(0.1);
const y = d3.scaleLinear().domain([0, d3.max(data)]).range([height - margin.bottom, margin.top]);

// Bars
svg.selectAll('rect')
  .data(data)
  .join('rect')
    .attr('x', (d, i) => x(i))
    .attr('y', d => y(d))
    .attr('width', x.bandwidth())
    .attr('height', d => y(0) - y(d))
    .attr('fill', 'steelblue');

// Axes
svg.append('g').attr('transform', `translate(0,${height - margin.bottom})`).call(d3.axisBottom(x));
svg.append('g').attr('transform', `translate(${margin.left},0)`).call(d3.axisLeft(y));
